esqlQuery.esql:
TS metrics-mongodbreceiver.otel-default
// Scope to MongoDB OTel metrics
| WHERE data_stream.dataset == "mongodbreceiver.otel"
| WHERE metrics.mongodb.memory.usage IS NOT NULL AND attributes.type == "resident"
// Resident memory is server-wide but emitted per database; use MAX to avoid double-counting
| STATS resident_bytes = MAX(LAST_OVER_TIME(metrics.mongodb.memory.usage)) BY resource.attributes.server.address
// Alert when resident memory exceeds 4GB (adjust for your host RAM)
| WHERE resident_bytes > 4294967296
| SORT resident_bytes DESC
| LIMIT 20
